-- ── Lesson 6 ────────────────────────────────────────────────
UPDATE english_lesson_sections
SET content = $json${
  "title": "Carbon Footprint: Individual Action and Collective Responsibility",
  "text": "A carbon footprint is the total amount of greenhouse gases — primarily carbon dioxide and methane — produced directly or indirectly by a person, organisation, or activity. Measuring carbon footprints has become a widely used tool for understanding the environmental impact of different lifestyles and consumption choices. The concept was popularised in part by oil company marketing campaigns in the early 2000s, which shifted public focus towards individual responsibility and away from corporate and systemic causes of emissions. Today, the debate about individual versus systemic action on climate change is actively contested. On one hand, individual choices genuinely matter. Food systems are responsible for around a third of global greenhouse gas emissions. Switching to a predominantly plant-based diet, reducing air travel, driving less, and choosing energy-efficient homes can significantly reduce personal emissions. Research suggests that the highest-income individuals have carbon footprints many times larger than those of people on average incomes, suggesting that targeted changes by the wealthy could have significant impact. On the other hand, critics argue that emphasising personal responsibility distracts from the systemic changes needed. Most people have limited options: they drive because there is no public transport, they eat cheap food because healthy alternatives are unaffordable, they fly because no train connection exists. Without policy changes that make low-carbon options available and affordable, individual behaviour change can only go so far. The most effective approach combines strong government policy — carbon taxes, clean energy investment, sustainable agriculture — with cultural shifts that make low-carbon choices normal and desirable. Individual action and systemic change are not alternatives but complements.",
  "glossary": [
    {"term": "carbon footprint", "definition": "the total greenhouse gas emissions caused directly or indirectly by a person or organisation", "translation": "углеродный след"},
    {"term": "methane", "definition": "a powerful greenhouse gas produced by livestock, landfills, and fossil fuel extraction", "translation": "метан"},
    {"term": "systemic", "definition": "relating to the underlying system or structure rather than individual elements", "translation": "системный"},
    {"term": "consumption", "definition": "the use of goods, services, and resources", "translation": "потребление"},
    {"term": "carbon tax", "definition": "a charge on the carbon content of fuels designed to reduce greenhouse gas emissions", "translation": "углеродный налог"},
    {"term": "predominantly", "definition": "mainly; for the most part", "translation": "преимущественно"}
  ],
  "comprehension_questions": [
    {"id": 1, "question": "What is a carbon footprint as defined in the passage?", "options": ["A) The area of land needed to absorb an individual's carbon emissions", "B) The total greenhouse gases produced directly or indirectly by a person or activity", "C) The amount of carbon dioxide released by burning fossil fuels", "D) A measurement of deforestation caused by consumer choices"], "answer": "B", "explanation": "A carbon footprint is the total amount of greenhouse gases produced directly or indirectly by a person, organisation, or activity."},
    {"id": 2, "question": "Who popularised the concept of carbon footprints, and why does this matter according to the passage?", "options": ["A) Environmental scientists, to help people make better choices", "B) Oil companies, partly to shift focus towards individual responsibility", "C) Governments, to encourage citizens to reduce emissions", "D) Non-governmental organisations, to raise awareness of climate change"], "answer": "B", "explanation": "The concept was popularised in part by oil company marketing campaigns that shifted focus towards individual responsibility and away from systemic causes."},
    {"id": 3, "question": "What proportion of global greenhouse gas emissions come from food systems?", "options": ["A) Around ten percent", "B) Around a fifth", "C) Around a third", "D) Around half"], "answer": "C", "explanation": "Food systems are responsible for around a third of global greenhouse gas emissions."},
    {"id": 4, "question": "What is the main argument made by critics who emphasise systemic change over individual action?", "options": ["A) Individual choices have no measurable impact on emissions", "B) Most people lack the options needed to make genuinely low-carbon choices without policy support", "C) Only the wealthiest individuals can afford to reduce their carbon footprint", "D) Government policy is always more effective than market-based solutions"], "answer": "B", "explanation": "Critics argue that most people have limited options — they drive, eat cheap food, and fly because lower-carbon alternatives are not available or affordable."},
    {"id": 5, "question": "What does the passage say about the relationship between individual action and systemic change?", "options": ["A) Individual action is more important than systemic change", "B) Systemic change is more important and individual action is irrelevant", "C) Individual action and systemic change are alternatives to be chosen between", "D) Individual action and systemic change are complements, not alternatives"], "answer": "D", "explanation": "The passage concludes that individual action and systemic change are not alternatives but complements."}
  ],
  "true_false_questions": [
    {"id": 1, "statement": "A carbon footprint measures only the direct emissions produced by a person through activities like driving.", "answer": false, "evidence": "A carbon footprint includes the total greenhouse gases produced directly OR indirectly by a person, organisation, or activity."},
    {"id": 2, "statement": "Oil companies played a role in making carbon footprints a popular concept.", "answer": true, "evidence": "The concept was popularised in part by oil company marketing campaigns in the early 2000s."},
    {"id": 3, "statement": "High-income individuals tend to have smaller carbon footprints than people on average incomes.", "answer": false, "evidence": "Research suggests that the highest-income individuals have carbon footprints many times larger than those of people on average incomes."},
    {"id": 4, "statement": "The passage argues that individual behaviour change is sufficient on its own to address climate change.", "answer": false, "evidence": "Without policy changes that make low-carbon options available and affordable, individual behaviour change can only go so far."},
    {"id": 5, "statement": "Strong government policy and cultural shifts towards low-carbon choices are described as part of the most effective approach.", "answer": true, "evidence": "The most effective approach combines strong government policy with cultural shifts that make low-carbon choices normal and desirable."}
  ],
  "vocabulary_in_context": [
    {"id": 1, "sentence": "The total greenhouse gases produced by a person's activities — their [BLANK] — can be measured and compared across different lifestyles.", "options": ["A) ecological impact", "B) carbon footprint", "C) energy consumption", "D) climate contribution"], "answer": "B", "explanation": "Carbon footprint is the specific term for the total greenhouse gas emissions caused by a person or activity."},
    {"id": 2, "sentence": "Switching to a [BLANK] plant-based diet — eating mostly plants but not necessarily exclusively — can significantly reduce emissions from food.", "options": ["A) completely", "B) primarily", "C) predominantly", "D) partially"], "answer": "C", "explanation": "Predominantly means mainly or for the most part, which is the word used in the passage."},
    {"id": 3, "sentence": "Critics argue that the focus on individual responsibility distracts from the [BLANK] changes needed — changes to the underlying policies and structures.", "options": ["A) political", "B) economic", "C) systemic", "D) cultural"], "answer": "C", "explanation": "Systemic means relating to the underlying system or structure, which is what critics argue needs to change."},
    {"id": 4, "sentence": "A [BLANK] — a charge on the carbon content of fuels — is one policy tool governments can use to incentivise lower emissions.", "options": ["A) carbon tax", "B) green levy", "C) fuel surcharge", "D) climate fee"], "answer": "A", "explanation": "Carbon tax is the specific policy instrument defined in the passage as a charge on the carbon content of fuels."}
  ],
  "critical_thinking": [
    {"id": 1, "question": "The passage reveals that oil companies helped popularise the concept of the carbon footprint to shift blame to individuals. How does knowing this change your view of individual responsibility for climate change?", "suggested_answer": "Knowing that the carbon footprint concept was partly a corporate marketing strategy does not eliminate individual responsibility, but it does help reframe it. It shows that emphasis on personal behaviour change can be a distraction from the much larger question of who controls energy systems, agricultural practices, and industrial processes. Individuals can and should make better choices, but the structural decisions made by corporations and governments have far greater impact. Critical awareness of how responsibility is framed helps us direct our energy towards systemic change while still making the personal changes within our control."},
    {"id": 2, "question": "The passage argues that low-carbon choices are often not available or affordable for most people. Is this a reason to focus only on policy, or should individuals still try to reduce their own footprint?", "suggested_answer": "Individual action and policy change are not in competition — both are needed. Individuals who can afford to choose lower-carbon lifestyles should do so, both for direct impact and because consumer behaviour can drive market changes. However, it would be wrong to judge or burden those who lack the resources or options to make different choices. The role of policy is precisely to make better choices available and affordable to everyone, not only the privileged. Demanding policy change is itself a form of individual action that may have more systemic impact than any single lifestyle choice."}
  ]
}$json$::jsonb
WHERE lesson_id = (
  SELECT l.id FROM english_lessons l
  JOIN english_modules m ON l.module_id = m.id
  JOIN english_courses c ON m.course_id = c.id
  WHERE c.title = 'B1 Intermediate' AND c.category = 'General English'
    AND m.order_index = 3 AND l.order_index = 6
) AND type = 'reading';

-- ── Lesson 7 ────────────────────────────────────────────────
UPDATE english_lesson_sections
SET content = $json${
  "title": "Youth Climate Activism: A Generation Demands Change",
  "text": "In August 2018, a fifteen-year-old Swedish student named Greta Thunberg began a school strike outside the Swedish parliament, demanding stronger government action on climate change. Within months, her solitary protest had inspired a global movement. By March 2019, more than one and a half million students in over one hundred countries had joined strikes under the banner of Fridays for Future. The movement drew attention to what many young people see as a fundamental injustice: they will live through the worst consequences of climate change caused primarily by earlier generations. Youth climate activism did not begin with Thunberg, but she gave it unprecedented global visibility. Young activists have used social media effectively to organise protests, share information, and reach audiences that traditional political organisations cannot. The visual and emotional power of young people demanding action has proven difficult for politicians to ignore, even if substantive policy responses have often been slow to follow. Critics of youth climate activism argue that young people lack the technical expertise and life experience necessary to develop effective policy solutions. Others suggest that some aspects of the movement have become counterproductive, focusing on individual guilt and emotional appeals rather than practical solutions. However, supporters argue that the political system has failed to respond adequately to decades of scientific warnings, and that urgent emotional appeals are precisely what is needed to break through political inertia. Research on social movements suggests that disruptive protest can shift public opinion and create the political conditions in which policy change becomes possible. Youth climate activism represents a continuation of a long tradition of young people challenging established power structures to demand a more just future.",
  "glossary": [
    {"term": "activism", "definition": "the use of direct and public action to achieve political or social goals", "translation": "активизм"},
    {"term": "strike", "definition": "a period of organised refusal to work or attend school as a form of protest", "translation": "забастовка"},
    {"term": "inertia", "definition": "a tendency to do nothing or to remain unchanged despite the need for action", "translation": "инерция"},
    {"term": "substantive", "definition": "having real importance, significance, or practical effect", "translation": "существенный, конкретный"},
    {"term": "injustice", "definition": "a situation where people are treated unfairly or do not receive what they deserve", "translation": "несправедливость"},
    {"term": "disruptive", "definition": "causing interruption or disturbance to the normal course of events", "translation": "разрушительный, нарушающий порядок"}
  ],
  "comprehension_questions": [
    {"id": 1, "question": "How did the Fridays for Future movement begin?", "options": ["A) Through a viral social media campaign launched by a group of activists", "B) With Greta Thunberg striking alone outside the Swedish parliament in 2018", "C) As an organised international event planned by environmental organisations", "D) With a student petition signed by millions across Europe"], "answer": "B", "explanation": "In August 2018, fifteen-year-old Greta Thunberg began a school strike outside the Swedish parliament, inspiring a global movement."},
    {"id": 2, "question": "How many students had joined climate strikes by March 2019?", "options": ["A) Around five hundred thousand", "B) Around one million", "C) More than one and a half million", "D) More than three million"], "answer": "C", "explanation": "By March 2019, more than one and a half million students in over one hundred countries had joined strikes."},
    {"id": 3, "question": "What fundamental injustice does the passage describe young climate activists as highlighting?", "options": ["A) That young people pay higher taxes than older generations", "B) That young people will live through the worst consequences of climate change caused by earlier generations", "C) That young people are excluded from formal political decision-making processes", "D) That environmental education is inadequate in schools worldwide"], "answer": "B", "explanation": "Many young people see it as a fundamental injustice that they will live through the worst consequences of climate change caused primarily by earlier generations."},
    {"id": 4, "question": "What advantage of social media does the passage mention in relation to youth activism?", "options": ["A) It allows young people to vote on policy decisions directly", "B) It makes protests more professional and better organised", "C) It enables young people to organise, share information, and reach audiences traditional politics cannot", "D) It provides funding for activist organisations through online donations"], "answer": "C", "explanation": "Young activists have used social media to organise protests, share information, and reach audiences that traditional political organisations cannot."},
    {"id": 5, "question": "What does research on social movements suggest about disruptive protest?", "options": ["A) It usually backfires by alienating the public and reducing support", "B) It can shift public opinion and create conditions in which policy change becomes possible", "C) It is only effective when supported by established political parties", "D) It works best when focused on economic arguments rather than emotional appeals"], "answer": "B", "explanation": "Research suggests that disruptive protest can shift public opinion and create the political conditions in which policy change becomes possible."}
  ],
  "true_false_questions": [
    {"id": 1, "statement": "Youth climate activism began with Greta Thunberg and had no history before 2018.", "answer": false, "evidence": "Youth climate activism did not begin with Thunberg, but she gave it unprecedented global visibility."},
    {"id": 2, "statement": "Politicians found the visual power of youth climate protests difficult to ignore.", "answer": true, "evidence": "The visual and emotional power of young people demanding action has proven difficult for politicians to ignore."},
    {"id": 3, "statement": "All commentators agree that youth climate activism is effective and should be supported.", "answer": false, "evidence": "Critics argue that young people lack technical expertise, and others suggest some aspects have become counterproductive."},
    {"id": 4, "statement": "Supporters of youth activism argue that emotional appeals are appropriate given the political system has ignored scientific warnings.", "answer": true, "evidence": "Supporters argue that the political system has failed to respond adequately to decades of scientific warnings, and that urgent emotional appeals are precisely what is needed."},
    {"id": 5, "statement": "The passage presents youth climate activism as a completely new phenomenon with no connection to historical movements.", "answer": false, "evidence": "Youth climate activism represents a continuation of a long tradition of young people challenging established power structures."}
  ],
  "vocabulary_in_context": [
    {"id": 1, "sentence": "Greta Thunberg began a school [BLANK] outside the Swedish parliament, refusing to attend school until the government acted on climate change.", "options": ["A) protest", "B) march", "C) strike", "D) boycott"], "answer": "C", "explanation": "Strike is the specific word used in the passage — it refers to organised refusal to work or attend school as protest."},
    {"id": 2, "sentence": "Supporters argue that urgent emotional appeals are needed to break through political [BLANK] — the tendency to do nothing despite the need for action.", "options": ["A) resistance", "B) inertia", "C) opposition", "D) indifference"], "answer": "B", "explanation": "Inertia describes a tendency to remain unchanged despite the need for action, which is the word used in the passage."},
    {"id": 3, "sentence": "Substantive policy responses to climate activism have often been slow, despite the [BLANK] importance of the actions demanded.", "options": ["A) emotional", "B) symbolic", "C) substantive", "D) political"], "answer": "C", "explanation": "Substantive means having real importance and practical effect — it describes the significance of the policy responses needed."},
    {"id": 4, "sentence": "Research suggests that [BLANK] protest — causing interruption to normal events — can shift public opinion and create conditions for policy change.", "options": ["A) violent", "B) organised", "C) disruptive", "D) peaceful"], "answer": "C", "explanation": "Disruptive is the specific word used in the passage — it describes protest that causes interruption to the normal course of events."}
